515	/// C: `void luaV_finishget(lua_State *L, const TValue *t, TValue *key,
516	///                          StkId val, const TValue *slot)`
517	/// Finish a table-get with metamethod lookup.  `slot_was_none = true` means
518	/// `t` is not a table and we should look for `__index` on `t` itself.
519	pub(crate) fn finish_get(
520	    state: &mut LuaState,
521	    t_val: LuaValue,
522	    key: LuaValue,
523	    result_idx: StackIdx,
524	    slot_empty: bool,
525	) -> Result<(), LuaError> {
526	    // C: for (loop = 0; loop < MAXTAGLOOP; loop++)
527	    let mut t = t_val;
528	    for _loop in 0..MAX_TAG_LOOP {
529	        let tm: LuaValue;
530	        if slot_empty && !matches!(t, LuaValue::Table(_)) {
531	            // C: if (slot == NULL) { tm = luaT_gettmbyobj(L, t, TM_INDEX); }
532	            // C: if (l_unlikely(notm(tm))) luaG_typeerror(L, t, "index");
533	            tm = state.get_tm_by_obj(&t, TagMethod::Index);
534	            if matches!(tm, LuaValue::Nil) {
535	                return Err(LuaError::type_error(&t, "index"));
536	            }
537	        } else {
538	            // C: t is a table; tm = fasttm(L, hvalue(t)->metatable, TM_INDEX)
539	            // C: if (tm == NULL) { setnilvalue(s2v(val)); return; }
540	            let mt = state.table_metatable(&t);
541	            tm = state.fast_tm_table(mt.as_ref(), TagMethod::Index);
542	            if matches!(tm, LuaValue::Nil) {
543	                state.set_at(result_idx, LuaValue::Nil);
544	                return Ok(());
545	            }
546	        }
547	        // C: if (ttisfunction(tm)) { luaT_callTMres(...); return; }
548	        if matches!(tm, LuaValue::Function(_)) {
549	            state.call_tm_res(tm, &t, &key, result_idx)?;
550	            return Ok(());
551	        }
552	        // C: t = tm; try t[key] again
553	        t = tm.clone();
554	        // C: if (luaV_fastget(L, t, key, slot, luaH_get))
555	        if let Some(v) = state.fast_get(&t, &key)? {
556	            state.set_at(result_idx, v);
557	            return Ok(());
558	        }
559	        // else: loop — tail-call luaV_finishget
560	    }
561	    Err(LuaError::runtime(format_args!("'__index' chain too long; possible loop")))
562	}
