564	/// C: `void luaV_finishset(lua_State *L, const TValue *t, TValue *key,
565	///                          TValue *val, const TValue *slot)`
566	/// Finish a table-set with `__newindex` metamethod lookup.
567	pub(crate) fn finish_set(
568	    state: &mut LuaState,
569	    t_val: LuaValue,
570	    key: LuaValue,
571	    val: LuaValue,
572	    _slot_present: bool,
573	) -> Result<(), LuaError> {
574	    let mut t = t_val;
575	    for _loop in 0..MAX_TAG_LOOP {
576	        let tm: LuaValue;
577	        if matches!(t, LuaValue::Table(_)) {
578	            // C: tm = fasttm(L, h->metatable, TM_NEWINDEX)
579	            let mt = state.table_metatable(&t);
